"""
TRIP IPO Gauge - Server Flask pentru Render.com
Toate fisierele sunt embedded - nu necesita folder static/
"""
import re, time, threading, base64
from datetime import datetime
from flask import Flask, jsonify, Response

try:
    import requests
    from bs4 import BeautifulSoup
except ImportError:
    import os
    os.system("pip install requests beautifulsoup4 --quiet")
    import requests
    from bs4 import BeautifulSoup

app = Flask(__name__)

RETAIL_TOTAL = 41_750_000
REFRESH_SEC  = 5
BVB_URL = "https://www.bvb.ro/FinancialInstruments/Details/FinancialInstrumentsDetails.aspx?s=TRIP"

state = {"subscribed": 0, "timestamp": "—", "error": None}

SESSION = requests.Session()
SESSION.headers.update({
    "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
    "Accept": "text/html,application/xhtml+xml;q=0.9,*/*;q=0.8",
    "Accept-Language": "ro-RO,ro;q=0.9,en;q=0.8",
    "Referer": "https://www.bvb.ro/",
})

def fetch_bid_vol():
    try:
        r = SESSION.get(BVB_URL, timeout=10)
        r.raise_for_status()
        soup = BeautifulSoup(r.text, "html.parser")
        text = soup.get_text(separator="|")
        match = re.search(r"Bid\s*/\s*Ask\s*Vol\.?\s*\|?\s*([\d\.]+)\s*/", text, re.IGNORECASE)
        if match:
            raw = match.group(1).replace(".", "").replace(",", "")
            return int(raw), None
        for td in soup.find_all("td"):
            if "Bid" in td.get_text() and "Vol" in td.get_text():
                sib = td.find_next_sibling("td")
                if sib:
                    nums = re.findall(r"[\d\.]+", sib.get_text(strip=True))
                    if nums:
                        return int(nums[0].replace(".", "")), None
        return None, "Nu s-a gasit Bid Vol"
    except Exception as e:
        return None, str(e)

def refresh_loop():
    while True:
        val, err = fetch_bid_vol()
        ts = datetime.now().strftime("%H:%M:%S")
        state["timestamp"] = ts
        if val is not None:
            state["subscribed"] = val
            state["error"] = None
            pct = round(val / RETAIL_TOTAL * 100, 1)
            print(f"[{ts}] {val:,} -> {pct}%", flush=True)
        else:
            state["error"] = err
            print(f"[{ts}] Eroare: {err}", flush=True)
        time.sleep(REFRESH_SEC)

t = threading.Thread(target=refresh_loop, daemon=True)
t.start()

# ── Embedded assets (base64) ──────────────────────────────────
_HTML_B64    = ""
_ICON192_B64 = ""
_ICON512_B64 = ""

HTML_BYTES = base64.b64decode(_HTML_B64)

# ── Routes ────────────────────────────────────────────────────
@app.route("/")
def index():
    return Response(HTML_BYTES, mimetype="text/html; charset=utf-8")

@app.route("/data")
def data():
    return jsonify(state)

@app.route("/icon-192.png")
def icon192():
    return Response(base64.b64decode(_ICON192_B64), mimetype="image/png")

@app.route("/icon-512.png")
def icon512():
    return Response(base64.b64decode(_ICON512_B64), mimetype="image/png")

@app.route("/manifest.json")
def manifest():
    return jsonify({
        "name": "TRIP IPO Gauge",
        "short_name": "TRIP IPO",
        "description": "Christian Tour IPO - Subscrieri Retail Live",
        "start_url": "/",
        "display": "standalone",
        "background_color": "#f1f5f9",
        "theme_color": "#00AEEF",
        "orientation": "portrait",
        "icons": [
            {"src": "/icon-192.png", "sizes": "192x192", "type": "image/png"},
            {"src": "/icon-512.png", "sizes": "512x512", "type": "image/png"}
        ]
    })

@app.route("/sw.js")
def sw():
    js = "self.addEventListener('install', e => self.skipWaiting());\n"
    js += "self.addEventListener('activate', e => clients.claim());\n"
    js += "self.addEventListener('fetch', e => { if (e.request.url.includes('/data')) return; e.respondWith(fetch(e.request).catch(() => caches.match(e.request))); });\n"
    return Response(js, mimetype="application/javascript")

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8765, debug=False)
